//  Mood Analysis Engine

// Keyword-based mood detection
export const analyzeMood = (text) => {
  const lowerText = text.toLowerCase();

  const moodKeywords = {
    happy: ["happy", "great", "excellent", "awesome", "wonderful", "amazing", "love", "excited", "glad", "fantastic"],
    sad: ["sad", "depressed", "unhappy", "miserable", "down", "upset", "broken", "hurt", "lonely", "crying"],
    anxious: ["anxious", "worried", "nervous", "stressed", "panic", "afraid", "scared", "overwhelmed", "tense", "uneasy"],
    angry: ["angry", "furious", "rage", "irritated", "annoyed", "frustrated", "mad", "bitter", "resentful"],
    calm: ["calm", "peaceful", "relaxed", "serene", "tranquil", "comfortable", "cozy", "safe"],
    neutral: ["okay", "fine", "alright", "normal", "regular", "average"]
  };

  let detectedMood = "neutral";
  let confidence = 0;

  for (const [mood, keywords] of Object.entries(moodKeywords)) {
    const matches = keywords.filter(keyword => lowerText.includes(keyword)).length;
    const moodConfidence = matches / keywords.length;

    if (moodConfidence > confidence) {
      confidence = moodConfidence;
      detectedMood = mood;
    }
  }

  return {
    mood: detectedMood,
    confidence: Math.round(confidence * 100),
    timestamp: new Date().toLocaleString(),
    source: "text"
  };
};

// Mood detection from facial expression (0-1 scores from face-api)
export const analyzeFacialMood = (expressions) => {
  if (!expressions) {
    return { mood: "neutral", confidence: 0, source: "face" };
  }

  // face-api returns emotion scores
  let detectedMood = "neutral";
  let maxScore = 0;

  const emotionMap = {
    happy: expressions.happy || 0,
    sad: expressions.sad || 0,
    angry: expressions.angry || 0,
    fearful: expressions.fearful || 0,
    disgusted: expressions.disgusted || 0,
    surprised: expressions.surprised || 0,
    neutral: expressions.neutral || 0
  };

  for (const [emotion, score] of Object.entries(emotionMap)) {
    if (score > maxScore) {
      maxScore = score;
      detectedMood = emotion === "fearful" ? "anxious" : emotion;
    }
  }

  return {
    mood: detectedMood,
    confidence: Math.round(maxScore * 100),
    timestamp: new Date().toLocaleString(),
    source: "face",
    expressions: emotionMap
  };
};

// Save mood to localStorage
export const saveMood = (moodData) => {
  const history = JSON.parse(localStorage.getItem("moodHistory")) || [];
  history.push(moodData);

  // Keep only last 30 moods
  if (history.length > 30) {
    history.shift();
  }

  localStorage.setItem("moodHistory", JSON.stringify(history));
  return history;
};

// Get mood statistics
export const getMoodStats = () => {
  const history = JSON.parse(localStorage.getItem("moodHistory")) || [];

  const stats = {
    total: history.length,
    byMood: {},
    bySource: { text: 0, face: 0 },
    recent: history.slice(-7)
  };

  history.forEach(entry => {
    stats.byMood[entry.mood] = (stats.byMood[entry.mood] || 0) + 1;
    stats.bySource[entry.source] = (stats.bySource[entry.source] || 0) + 1;
  });

  return stats;
};

// Clear mood history
export const clearMoodHistory = () => {
  localStorage.removeItem("moodHistory");
};
